</head>
<body>
    <canvas id="sand" width="400" height="400"></canvas>
    <div class="controls">
        <button id="mat-sand">Sand</button>
        <button id="mat-water">Water</button>
        <button id="mat-wall">Wall</button>
        <button id="mat-acid">Acid</button>
        <button id="mat-empty">Erase</button>
        <button id="clear">Clear All</button>
    </div>

    <script>
        const w = 80;
        const h = 80;
        const scale = 5;

        let grid = new Array(w).fill(0).map(() => new Array(h).fill('empty'));
        let selectedMat = 'sand';

        const canvas = document.getElementById('sand');
        const ctx = canvas.getContext('2d');

        function render() {
            ctx.clearRect(0, 0, canvas.width, canvas.height);
            for (let x = 0; x < w; x++) {
                for (let y = 0; y < h; y++) {
                    let color;
                    switch(grid[x][y]) {
                        case 'sand': color = '#FFB41A'; break;
                        case 'water': color = '#378CE7'; break;
                        case 'wall': color = '#555'; break;
                        case 'acid': color = '#00ff00'; break;
                        default: color = '#121212';
                    }
                    ctx.fillStyle = color;
                    ctx.fillRect(x * scale, y * scale, scale, scale);
                }
            }
        }

        let isPainting = false;

        canvas.addEventListener('mousedown', (e) => {
            isPainting = true;
            updateCanvas(e);
        });

        canvas.addEventListener('mouseup', () => {
            isPainting = false;
        });

        canvas.addEventListener('mouseleave', () => {
            isPainting = false;
        });

        canvas.addEventListener('mousemove', (e) => {
            if (isPainting) updateCanvas(e);
        });

        function updateCanvas(e) {
            const rect = canvas.getBoundingClientRect();
            const x = Math.floor((e.clientX - rect.left) / scale);
            const y = Math.floor((e.clientY - rect.top) / scale);

            if (x >= 0 && x < w && y >= 0 && y < h) {
                let mat;
                switch(selectedMat) {
                    case 'sand': mat = 'sand'; break;
                    case 'water': mat = 'water'; break;
                    case 'wall': mat = 'wall'; break;
                    case 'acid': mat = 'acid'; break;
                    default: mat = 'empty';
                }
                grid[x][y] = mat;
            }
        }

        document.querySelectorAll('button').forEach(btn => {
            btn.addEventListener('click', () => {
                if (btn.id.startsWith('mat-')) selectedMat = btn.id.split('-')[1];
                else if (btn.id === 'clear') window.sim.clear();
            });
        });

        function shuffle(array) {
            for (let i = array.length - 1; i > 0; i--) {
                const j = Math.floor(Math.random() * (i + 1));
                [array[i], array[j]] = [array[j], array[i]];
            }
        }

        function swapCells(x1, y1, x2, y2) {
            const temp = grid[x1][y1];
            grid[x1][y1] = grid[x2][y2];
            grid[x2][y2] = temp;
        }

        function processSand(x, y) {
            if (y + 1 >= h) return;
            const belowMat = grid[x][y + 1];
            if (belowMat === 'empty' || belowMat === 'water' || belowMat === 'acid') {
                swapCells(x, y, x, y + 1);
                return;
            }

            const dirs = [[-1, 1], [1, 1]];
            shuffle(dirs);

            for (const [dx] of dirs) {
                const nx = x + dx;
                if (nx < 0 || nx >= w) continue;
                const targetMat = grid[nx][y + 1];
                if (targetMat === 'empty' || targetMat === 'water' || targetMat === 'acid') {
                    swapCells(x, y, nx, y + 1);
                    return;
                }
            }
        }

        function processWater(x, y) {
            if (y + 1 >= h) return;
            const belowMat = grid[x][y + 1];
            if (belowMat === 'empty') {
                swapCells(x, y, x, y + 1);
                return;
            }

            const dirs = [['left', -1], ['right', 1]];
            shuffle(dirs);

            for (const [dirName, dx] of dirs) {
                const nx = x + dx;
                if (nx < 0 || nx >= w) continue;
                const targetMat = grid[nx][y];
                if (targetMat === 'empty') {
                    swapCells(x, y, nx, y);
                    return;
                }
            }
        }

        function processAcidMovement(x, y) {
            if (y + 1 >= h) return;
            const belowMat = grid[x][y + 1];
            if (belowMat === 'empty') {
                swapCells(x, y, x, y + 1);
                return;
            }

            const dirs = [['left', -1], ['right', 1]];
            shuffle(dirs);

            for (const [dirName, dx] of dirs) {
                const nx = x + dx;
                if (nx < 0 || nx >= w) continue;
                const targetMat = grid[nx][y];
                if (targetMat === 'empty') {
                    swapCells(x, y, nx, y);
                    return;
                }
            }
        }

        function dissolveAcid(x, y) {
            const dirs = [
                [0, 1], [-1, 0], [1, 0]
            ];

            for (const [dx, dy] of dirs) {
                const nx = x + dx;
                const ny = y + dy;
                if (nx < 0 || nx >= w || ny < 0 || ny >= h) continue;
                const targetMat = grid[nx][ny];
                if (targetMat === 'sand' || targetMat === 'wall') {
                    grid[nx][ny] = 'empty';
                }
            }
        }

        function simulateStep() {
            for (let y = h - 1; y >= 0; y--) {
                for (let x = 0; x < w; x++) {
                    const mat = grid[x][y];
                    if (mat === 'empty' || mat === 'wall') continue;

                    switch(mat) {
                        case 'sand': processSand(x, y); break;
                        case 'water': processWater(x, y); break;
                        case 'acid': processAcidMovement(x, y); break;
                    }
                }
            }

            for (let y = h - 1; y >= 0; y--) {
                for (let x = 0; x < w; x++) {
                    if (grid[x][y] === 'acid') dissolveAcid(x, y);
                }
            }
        }

        let lastTime = 0;
        const FPS = 30;

        function animate(time) {
            const now = time;
            if (now - lastTime > 1000 / FPS) {
                simulateStep();
                render();
                lastTime = now;
            }
            requestAnimationFrame(animate);
        }
        requestAnimationFrame(animate);

        window.sim = {
            w: w,
            h: h,
            tick(n) {
                for (let i = 0; i < n; i++) simulateStep();
            },
            get(x, y) {
                if (x < 0 || x >= this.w || y < 0 || y >= this.h) return 'empty';
                return grid[x][y];
            },
            set(x, y, material) {
                if (x >= 0 && x < this.w && y >= 0 && y < this.h)
                    grid[x][y] = material;
            },
            clear() {
                for (let x = 0; x < w; x++) {
                    for (let y = 0; y < h; y++) {
                        grid[x][y] = 'empty';
                    }
                }
                render();
            }
        };

        render();
    </script>
