    </style>
</head>
<body>
    <div id="controls">
        <button id="mat-sand">Sand</button>
        <button id="mat-water">Water</button>
        <button id="mat-wall">Wall</button>
        <button id="mat-acid">Acid</button>
        <button id="mat-empty">Erase</button>
        <button id="clear">Clear All</button>
    </div>
    <canvas id="sand" width="400" height="400"></canvas>
    <script>
        const w = 80;
        const h = 80;
        const scale = 5;

        let grid = new Array(w);
        for (let x = 0; x < w; x++) {
            grid[x] = new Array(h).fill('empty');
        }

        function swapCells(x1, y1, x2, y2) {
            [grid[x1][y1], grid[x2][y2]] = [grid[x2][y2], grid[x1][y1]];
        }

        function shuffle(array) {
            for (let i = array.length - 1; i > 0; i--) {
                const j = Math.floor(Math.random() * (i + 1));
                [array[i], array[j]] = [array[j], array[i]];
            }
        }

        function moveSand(x, y) {
            let newX = x;
            let newY = y;
            const belowY = y + 1;
            if (belowY < h) {
                const belowMat = grid[x][belowY];
                if (belowMat === 'empty') {
                    swapCells(x, y, x, belowY);
                    return { newX: x, newY: belowY };
                } else if (['water', 'acid'].includes(belowMat)) {
                    swapCells(x, y, x, belowY);
                    return { newX: x, newY: belowY };
                }
            }

            const directions = [-1, 1];
            shuffle(directions);
            for (let dx of directions) {
                let nx = x + dx;
                if (nx >= 0 && nx < w && belowY < h) {
                    const targetMat = grid[nx][belowY];
                    if (targetMat === 'empty') {
                        swapCells(x, y, nx, belowY);
                        return { newX: nx, newY: belowY };
                    }
                }
            }

            return { newX, newY };
        }

        function moveWater(x, y) {
            let newX = x;
            let newY = y;
            const belowY = y + 1;
            if (belowY < h && grid[x][belowY] === 'empty') {
                swapCells(x, y, x, belowY);
                return { newX: x, newY: belowY };
            }

            const directions = [-1, 1];
            shuffle(directions);
            for (let dx of directions) {
                let nx = x + dx;
                if (nx >= 0 && nx < w && belowY < h) {
                    if (grid[nx][belowY] === 'empty') {
                        swapCells(x, y, nx, belowY);
                        return { newX: nx, newY: belowY };
                    }
                }
            }

            return { newX, newY };
        }

        function moveAcid(x, y) {
            let newX = x;
            let newY = y;
            const belowY = y + 1;
            if (belowY < h && grid[x][belowY] === 'empty') {
                swapCells(x, y, x, belowY);
                return { newX: x, newY: belowY };
            }

            const directions = [-1, 1];
            shuffle(directions);
            for (let dx of directions) {
                let nx = x + dx;
                if (nx >= 0 && nx < w && belowY < h) {
                    if (grid[nx][belowY] === 'empty') {
                        swapCells(x, y, nx, belowY);
                        return { newX: nx, newY: belowY };
                    }
                }
            }

            return { newX, newY };
        }

        function checkDissolution(x, y) {
            const positions = [
                [x, y + 1], // down
                [x - 1, y], // left
                [x + 1, y]  // right
            ];
            for (let [tx, ty] of positions) {
                if (ty >= 0 && ty < h && tx >= 0 && tx < w) {
                    const mat = grid[tx][ty];
                    if (mat === 'sand' || mat === 'wall') {
                        grid[tx][ty] = 'empty';
                    }
                }
            }
        }

        function processCell(x, y) {
            let mat = grid[x][y];
            if (mat === 'empty' || mat === 'wall') return;
            let result;

            if (mat === 'sand') {
                result = moveSand(x, y);
            } else if (mat === 'water') {
                result = moveWater(x, y);
            } else if (mat === 'acid') {
                result = moveAcid(x, y);
            }

            const { newX, newY } = result;
            if (mat === 'acid') checkDissolution(newX, newY);
        }

        function simulateStep() {
            for (let y = h - 1; y >= 0; y--) {
                for (let x = 0; x < w; x++) {
                    processCell(x, y);
                }
            }
        }

        function render() {
            const canvas = document.getElementById('sand');
            const ctx = canvas.getContext('2d');
            ctx.fillStyle = '#1e1e1e';
            ctx.fillRect(0, 0, canvas.width, canvas.height);
            for (let x = 0; x < w; x++) {
                for (let y = 0; y < h; y++) {
                    const mat = grid[x][y];
                    if (mat === 'empty') continue;
                    let color;
                    if (mat === 'sand') color = '#FFD700';
                    else if (mat === 'water') color = '#1E90FF';
                    else if (mat === 'wall') color = '#808080';
                    else if (mat === 'acid') color = '#00FF00';
                    ctx.fillStyle = color;
                    ctx.fillRect(x * scale, y * scale, scale, scale);
                }
            }
        }

        function animate() {
            simulateStep();
            render();
            requestAnimationFrame(animate);
        }

        let selectedMaterial = 'sand';

        document.getElementById('mat-sand').onclick = () => selectedMaterial = 'sand';
        document.getElementById('mat-water').onclick = () => selectedMaterial = 'water';
        document.getElementById('mat-wall').onclick = () => selectedMaterial = 'wall';
        document.getElementById('mat-acid').onclick = () => selectedMaterial = 'acid';
        document.getElementById('mat-empty').onclick = () => selectedMaterial = 'empty';
        document.getElementById('clear').onclick = () => {
            for (let x = 0; x < w; x++) {
                for (let y = 0; y < h; y++) {
                    grid[x][y] = 'empty';
                }
            }
        };

        const canvas = document.getElementById('sand');
        let isDragging = false;

        function handleMouse(e) {
            const rect = canvas.getBoundingClientRect();
            const x = Math.floor((e.clientX - rect.left) / scale);
            const y = Math.floor((e.clientY - rect.top) / scale);
            if (x >= 0 && x < w && y >= 0 && y < h) {
                grid[x][y] = selectedMaterial;
            }
        }

        canvas.addEventListener('mousedown', e => {
            isDragging = true;
            handleMouse(e);
        });
        canvas.addEventListener('mousemove', e => {
            if (isDragging) handleMouse(e);
        });
        canvas.addEventListener('mouseup', () => isDragging = false);
        canvas.addEventListener('mouseleave', () => isDragging = false);

        window.sim = {
            w,
            h,
            tick(n) {
                for (let i = 0; i < n; i++) simulateStep();
            },
            get(x, y) {
                if (x >= 0 && x < w && y >= 0 && y < h) return grid[x][y];
                return 'empty';
            },
            set(x, y, material) {
                if (x >= 0 && x < w && y >= 0 && y < h) grid[x][y] = material;
            },
            clear() {
                for (let x = 0; x < w; x++) {
                    for (let y = 0; y < h; y++) {
                        grid[x][y] = 'empty';
                    }
                }
            }
        };

        requestAnimationFrame(animate);
    </script>
</body>
</html>
